{"code": "import json
import re

# Read the full language data from the file
language_file_path = locals().get('var_functions.query_db:8')
language_data = []
if isinstance(language_file_path, str) and language_file_path.endswith('.json'):
    with open(language_file_path, 'r') as f:
        language_data = json.load(f)

# Read commit data
commit_data = locals().get('var_functions.query_db:22', [])
if isinstance(commit_data, str):
    with open(commit_data, 'r') as f:
        commit_data = json.load(f)

# Check if torvalds/linux exists in language data
torvalds_linux_in_language = any(item['repo_name'] == 'torvalds/linux' for item in language_data)

# Debug: Find matching repos
commit_repos = {item['repo_name'] for item in commit_data}
matched_repos = []

for commit_repo in commit_data:
    repo_name = commit_repo['repo_name']
    language_record = next((lang for lang in language_data if lang['repo_name'] == repo_name), None)
    if language_record:
        matched_repos.append({
            'repo_name': repo_name,
            'commit_count': int(commit_repo['commit_count']),
            'language': language_record['language_description']
        })
    else:
        matched_repos.append({
            'repo_name': repo_name,
            'commit_count': int(commit_repo['commit_count']),
            'language': 'NOT_FOUND'
        })

print('__RESULT__:')
print(json.dumps({
    'torvalds_linux_in_language': torvalds_linux_in_language,
    'total_language_records': len(language_data),
    'matched_repos': matched_repos
}))"}

